import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void firstIsUnique() {
        // l appears once → index 0
        assertEquals(0, new Solution().firstUniqueChar("leetcode"));
    }

    @Test
    void skipRepeats() {
        // l@0 (×2), o@1 (×2), v@2 (unique) → index 2
        assertEquals(2, new Solution().firstUniqueChar("loveleetcode"));
    }

    @Test
    void allRepeat() {
        assertEquals(-1, new Solution().firstUniqueChar("aabb"));
    }

    @Test
    void single() {
        assertEquals(0, new Solution().firstUniqueChar("z"));
    }

    @Test
    void empty() {
        assertEquals(-1, new Solution().firstUniqueChar(""));
    }
}
